function.body:
-- Logistice
	v_ResultStr		VARCHAR2(2000) := '';
	v_Message		VARCHAR2(2000) := '';
    TYPE RECORD IS REF CURSOR;
    Cur				RECORD;
	-- Variables
	vRecordID		VARCHAR2(32);
	vInvoice			RECORD;
	vUserID 		VARCHAR2(60);

BEGIN
	-- Begin Get Parameters
	FOR Cur IN (
		SELECT *
		FROM ad_ep_instance_para
		WHERE ad_ep_instance_id = PInstance_ID
	) LOOP
		IF Cur.ParameterName = 'Record_ID' THEN
			vRecordID := Cur.P_String;
		ELSEIF Cur.ParameterName = 'User' THEN
			vUserID := Cur.P_String;
		END IF;	
	END LOOP;
	-- Finish Get Parameter

	--<<BEGIN_PROCESS>>

	SELECT i.c_invoice_id
	, i.grandtotal
	, COALESCE(em_sbpc_invoice_limit_amount,0) AS invoice_limit_amount
	, COALESCE(bp.name,'') as tercero
    INTO vInvoice
    FROM c_invoice i
	JOIN c_bpartner bp ON bp.c_bpartner_id=i.c_bpartner_id
    WHERE i.c_invoice_id = vRecordID AND docstatus='DR' AND issotrx='Y';

	IF vInvoice.invoice_limit_amount > 0 AND vInvoice.grandtotal > vInvoice.invoice_limit_amount THEN

		RAISE_APPLICATION_ERROR(-20000, 'El valor procesado excede al valor permitido para el Tercero: <b>'||vInvoice.tercero||'</b>, Valor actual permitido: <b>'||vInvoice.invoice_limit_amount||'</b>');

	END IF; 

	--<<FINISH_PROCESS>>

	RETURN v_ResultStr;
END SBPC_AMOUNT_INVOICE
